const fs = require('fs');
const path = require('path');

const PROJECT = '/mnt/d/NAS-DATA/antenna-engine';
const input = $json;

// Parse error information
const phase = input.phase || 'unknown';
const error = input.error || {};

// Determine which files to read based on phase
const fileMap = {
  'cad-import': ['src-tauri/src/core/import.rs', 'src-tauri/src/core/import_stl.rs', 'src-tauri/src/core/import_nec.rs', 'src-tauri/src/core/import_nastran.rs', 'src-tauri/src/core/mod.rs'],
  'mesh-gen': ['src-tauri/src/core/mesher.rs', 'src-tauri/src/core/rwg.rs', 'src-tauri/src/core/mesh_refine.rs', 'src-tauri/src/core/geometry.rs', 'src-tauri/src/core/mod.rs'],
  'mom-solver': ['src-tauri/src/core/solver.rs', 'src-tauri/src/core/mom_surface.rs', 'src-tauri/src/core/linalg.rs', 'src-tauri/src/core/green.rs', 'src-tauri/src/core/impedance.rs', 'src-tauri/src/core/port.rs', 'src-tauri/src/bridge.rs', 'src-tauri/src/core/mod.rs'],
  'fdtd-python': ['python/antenna_ml/fdtd/yee_grid.py', 'python/antenna_ml/fdtd/pml.py', 'python/antenna_ml/fdtd/sources.py', 'python/antenna_ml/fdtd/runner.py', 'src-tauri/src/core/fdtd_bridge.rs'],
  'frontend': ['src/App.tsx', 'src/components/FileImport/FileImport.tsx', 'src/viewport/MeshViewer.tsx', 'src/components/SolverPanel/SolverPanel.tsx', 'src/components/SolverPanel/SolverProgress.tsx', 'src/components/SolverPanel/ResultsView.tsx'],
  'tests': ['src-tauri/src/core/benchmark_antennas.rs', 'python/tests/test_benchmark.py', 'src/tests/integration.test.ts'],
};

const filesToRead = fileMap[phase] || [];
const fileContents = {};

for (const f of filesToRead) {
  const fullPath = path.join(PROJECT, f);
  try {
    fileContents[f] = fs.readFileSync(fullPath, 'utf8');
  } catch {
    fileContents[f] = '// FILE NOT FOUND';
  }
}

// Also run cargo check / tsc to get fresh errors
const { execSync } = require('child_process');
let freshErrors = '';
try {
  if (phase === 'frontend') {
    freshErrors = execSync('npx tsc --noEmit 2>&1', { cwd: PROJECT, timeout: 60000 }).toString();
  } else if (phase === 'fdtd-python') {
    freshErrors = execSync('python3 -m py_compile python/antenna_ml/fdtd/runner.py 2>&1', { cwd: PROJECT, timeout: 30000 }).toString();
  } else {
    freshErrors = execSync('cd src-tauri && cargo check 2>&1', { cwd: PROJECT, timeout: 180000 }).toString();
  }
} catch (e) {
  freshErrors = e.stdout?.toString() || e.message;
}

const attempt = (input.state?.phases?.[phase]?.attempts || 0) + 1;
const useOpus = attempt >= 3;

return [{ json: { phase, error, fileContents, freshErrors, attempt, useOpus } }];

const { execSync } = require('child_process');
const fs = require('fs');
const path = require('path');

const PROJECT = '/mnt/d/NAS-DATA/antenna-engine';
const phase = $('Parse Errors + Read Files').item.json.phase;

// Apply fixes — get output from whichever agent ran
let output = '';
try { output = $('Fix Agent (Sonnet)').item.json.output || ''; } catch {}
try { if (!output) output = $('Fix Agent (Opus)').item.json.output || ''; } catch {}

const fileRegex = /<file path="([^"]+)">\n?([\s\S]*?)<\/file>/g;
const applied = {};
let match;

while ((match = fileRegex.exec(output)) !== null) {
  const fullPath = path.join(PROJECT, match[1]);
  const dir = path.dirname(fullPath);
  if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });
  fs.writeFileSync(fullPath, match[2].trim());
  applied[match[1]] = 'FIXED';
}

// Verify
let verifyResult = '';
try {
  if (phase === 'frontend') {
    verifyResult = execSync('npx tsc --noEmit 2>&1', { cwd: PROJECT, timeout: 120000 }).toString();
    if (!verifyResult.trim()) verifyResult = 'OK';
  } else if (phase === 'fdtd-python') {
    verifyResult = execSync('python3 -c "import antenna_ml.fdtd" 2>&1', { cwd: path.join(PROJECT, 'python'), timeout: 30000 }).toString();
    if (!verifyResult.trim()) verifyResult = 'OK';
  } else {
    verifyResult = execSync('cd src-tauri && cargo check 2>&1', { cwd: PROJECT, timeout: 180000 }).toString();
    verifyResult = verifyResult.includes('error[') ? verifyResult : 'OK';
  }
} catch (e) {
  verifyResult = e.stdout?.toString() || e.message;
}

const fixed = verifyResult === 'OK' || !verifyResult.includes('error');

// Hotfix logging
const logPath = path.join(PROJECT, '.claude/hotfix-log.json');
let log = [];
try { log = JSON.parse(fs.readFileSync(logPath, 'utf8')); } catch {}
log.push({
  timestamp: new Date().toISOString(),
  phase,
  attempt: $('Parse Errors + Read Files').item.json.attempt,
  model: $('Parse Errors + Read Files').item.json.attempt >= 3 ? 'opus' : 'sonnet',
  fixed: fixed,
  filesFixed: Object.keys(applied),
});
fs.writeFileSync(logPath, JSON.stringify(log, null, 2));

// Git commit if fixed
let gitResult = '';
if (fixed) {
  try {
    execSync('git add -A', { cwd: PROJECT });
    execSync(`git commit -m "fix(${phase}): hotfix compilation errors\n\nAuto-fix applied by ae-em-hotfix pipeline."`, { cwd: PROJECT });
    execSync('git push origin main', { cwd: PROJECT });
    gitResult = 'Committed and pushed';
  } catch (e) {
    gitResult = 'Git: ' + e.message;
  }
}

return [{ json: { phase, applied, verifyResult, fixed, gitResult, status: fixed ? 'complete' : 'still-broken' } }];

const attempt = $('Parse Errors + Read Files').item.json.attempt;
const maxAttempts = 5;

if (attempt >= maxAttempts) {
  return [{ json: { ...$('Apply + Verify').item.json, status: 'max-retries-reached', message: `Failed after ${maxAttempts} attempts` } }];
}

// Re-trigger: pass data back to Parse Errors node
return [{ json: { ...$('Apply + Verify').item.json, retry: true } }];
